class Solution {
    public int leastInterval(char[] tasks, int n) {
        int[] freq = new int[26];
        for (char t : tasks) freq[t - 'A']++;
        int maxf = 0;
        for (int f : freq) maxf = Math.max(maxf, f);
        int countMax = 0;
        for (int f : freq) if (f == maxf) countMax++;
        return Math.max(tasks.length, (maxf - 1) * (n + 1) + countMax);
    }
}

