class Solution:
    def leastInterval(self, tasks: list[str], n: int) -> int:
        from collections import Counter
        freq = Counter(tasks)
        maxf = max(freq.values())
        count_max = sum(1 for f in freq.values() if f == maxf)
        return max(len(tasks), (maxf - 1) * (n + 1) + count_max)

